#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdint.h>

#define MAXN 100005
#define MAXM 55
#define MAXQ 50005

typedef long long ll;

int main() {
    int T = 1;
    while (T--) {
        int N, M, Q;
        scanf("%d %d %d", &N, &M, &Q);
        ll X[N];
        for (int i = 0; i < N; i++) {
            scanf("%lld", &X[i]);
        }
        ll U[M][M];
        for (int i = 0; i < M; i++) {
            for (int j = 0; j < M; j++) {
                scanf("%lld", &U[i][j]);
            }
        }
        while (Q--) {
            int type;
            scanf("%d", &type);
            if (type == 1) {
                int A, B;
                scanf("%d %d", &A, &B);
                // calculate communication cost
            } else if (type == 2) {
                ll Y, R, C, T;
                scanf("%lld %lld %lld %lld", &Y, &R, &C, &T);
                // construct new tower
            }
        }
    }
    return 0;
}

